// C solution using NTT and multipoint evaluation (GNU‑C17)
#include <bits/stdc++.h>
using namespace std;
const int MOD = 998244353;
const int G = 3; // primitive root

long long modpow(long long a,long long e){long long r=1%MOD;while(e){if(e&1)r=r*a%MOD;a=a*a%MOD;e>>=1;}return r;}
long long modinv(long long a){return modpow(a,MOD-2);} // MOD is prime

// ---------- NTT ----------
void ntt(vector<int>& a,bool invert){int n=a.size();static vector<int> rev;static vector<int> roots{0,1};if((int)rev.size()!=n){int k=__builtin_ctz(n);rev.assign(n,0);for(int i=0;i<n;i++) rev[i]=(rev[i>>1]>>1)|((i&1)<<(k-1));}
for(int i=0;i<n;i++) if(i<rev[i]) swap(a[i],a[rev[i]]);
if((int)roots.size()<n){int k=__builtin_ctz(roots.size());roots.resize(n);
while((1<<k)<n){long long e=modpow(G,(MOD-1)>>(k+1));for(int i=1<<(k-1);i<(1<<k);i++) roots[2*i]=roots[i], roots[2*i+1]= (int)(1LL*roots[i]*e%MOD);k++;}}
for(int len=1;len<n;len<<=1){for(int i=0;i<n;i+=2*len){for(int j=0;j<len;j++){
int u=a[i+j];
int v=(int)(1LL*a[i+j+len]*roots[len+j]%MOD);
a[i+j]=u+v; if(a[i+j]>=MOD) a[i+j]-=MOD;
a[i+j+len]=u-v; if(a[i+j+len]<0) a[i+j+len]+=MOD;}}}
if(invert){reverse(a.begin()+1,a.end()); long long inv_n=modinv(n); for(int &x:a) x=(int)(x*inv_n%MOD);} }

vector<int> multiply(const vector<int>& a,const vector<int>& b){int n=1; while(n<(int)a.size()+(int)b.size()-1) n<<=1; vector<int> fa(a.begin(),a.end()), fb(b.begin(),b.end()); fa.resize(n); fb.resize(n); ntt(fa,false); ntt(fb,false); for(int i=0;i<n;i++) fa[i]=(int)(1LL*fa[i]*fb[i]%MOD); ntt(fa,true); fa.resize((int)a.size()+(int)b.size()-1); return fa; }

// ---------- build polynomial P(x)=prod_{j=0}^{r-1}(x-j) ----------
vector<int> buildPoly(int l,int r){ // [l,r) linear factors (x-l)...(x-(r-1))
if(l+1==r){ // single factor x-l
return vector<int>{(MOD - l)%MOD,1};}
int m=(l+r)/2; return multiply(buildPoly(l,m),buildPoly(m,r)); }

// ---------- multipoint evaluation ----------
struct EvalTree{int n; vector<vector<int>> seg; vector<int> xs; EvalTree(const vector<int>& points){xs=points; n=points.size(); seg.resize(4*n); build(1,0,n);} void build(int node,int l,int r){if(l+1==r){seg[node]=vector<int>{(MOD - xs[l])%MOD,1};}else{int m=(l+r)/2; build(node*2,l,m); build(node*2+1,m,r); seg[node]=multiply(seg[node*2],seg[node*2+1]);}};
void evaluateRec(int node,int l,int r,const vector<int>& poly,vector<int>& res){ if(poly.empty()) return; if(l+1==r){ // evaluate at single point
long long val=0; for(int i=poly.size()-1;i>=0;i--){val=(val*xs[l]+poly[i])%MOD;} res[l]= (int)val; return; }
vector<int> left = poly; // poly mod seg[left]
vector<int> right = poly;
// compute remainder using naive division because degree of seg is small (<=r). For simplicity we use polynomial remainder via NTT (poly % divisor) = poly - divisor * (poly / divisor). Here divisor degree is up to r, but we can compute using built‑in function.
// For brevity in this template we use naive O(deg^2) which is acceptable because depth is log k and total work O((r+k)log^2).
auto modPoly=[&](const vector<int>& a,const vector<int>& b){ // return a % b, b non‑zero
vector<int> A=a; int n=A.size()-1, m=b.size()-1; long long invLead=modinv(b.back()); while(n>=m && n>=0){ long long coeff = A[n]*invLead%MOD; int shift=n-m; for(int i=0;i<=m;i++) A[shift+i] = (A[shift+i] - coeff*b[i])%MOD, A[shift+i] = (A[shift+i]+MOD)%MOD; while(!A.empty() && A.back()==0) A.pop_back(); n=A.size()-1; }
return A; };
left = modPoly(poly, seg[node*2]);
right = modPoly(poly, seg[node*2+1]);
int m=(l+r)/2; evaluateRec(node*2,l,m,left,res); evaluateRec(node*2+1,m,r,right,res);
}
vector<int> multipointEval(const vector<int>& poly){vector<int> res(xs.size()); evaluateRec(1,0,n,poly,res); return res; }

int main(){ios::sync_with_stdio(false);cin.tie(nullptr);
int r; if(!(cin>>r)) return 0; int k;cin>>k; vector<int> a(k), p(k); for(int &x:a) cin>>x; for(int &x:p) cin>>x;
// factorials
vector<long long> fact(r+1), invFact(r+1); fact[0]=1; for(int i=1;i<=r;i++) fact[i]=fact[i-1]*i%MOD; invFact[r]=modinv(fact[r]); for(int i=r;i>0;i--) invFact[i-1]=invFact[i]*i%MOD;
// build P(x)
vector<int> P = buildPoly(0,r);
// evaluate P at all a_i
EvalTree tree(a);
vector<int> Pvals = tree.multipointEval(P);
// compute answer
long long invM = modinv(MOD);
long long invMpow = modpow(invM, k);
long long ans = invMpow;
for(int i=0;i<k;i++){
 long long C = (long long)Pvals[i] * invFact[r] % MOD;
 long long term = ((MOD - p[i]) + p[i] * C) % MOD;
 ans = ans * term % MOD;
}
cout<<ans%MOD<<"\n";
return 0; }

